const fs = require("fs");

module.exports = async ({ github, context }) => {
    const prFp = "./pr-stress-result.md";
    const masterFp = "./stress-result.md";

    let prSummary = "PR Benchmark Result not available!";
    let masterSummary = "Master Benchmark Result not available!";
    try {
        prSummary = fs.readFileSync(prFp, "utf8");
    } catch {}

    try {
        masterSummary = fs.readFileSync(masterFp, "utf8");
    } catch {}

    const body = `
## 🚀 k6 Load Test Results
### PR Benchmark result:
<details>
<summary>Click to view full report</summary>

\`\`\`text
${prSummary}
\`\`\`

</details>

### Master Benchmark result:
<details>
<summary>Click to view full report</summary>

\`\`\`text
${masterSummary}
\`\`\`

*Generated by GitHub Actions*`;

    await github.rest.issues.createComment({
        issue_number: context.issue.number,
        owner: context.repo.owner,
        repo: context.repo.repo,
        body: body,
    });
};
